/**
 * Vercel: если в проекте задан outputDirectory "public", каталог должен
 * появиться после `npm run build`. Nest кладёт артефакты в `dist/`, не в `public`.
 */
const fs = require('fs');
const path = require('path');

const dir = path.join(__dirname, '..', 'public');
fs.mkdirSync(dir, { recursive: true });
const marker = path.join(dir, '.vercel-output-placeholder');
if (!fs.existsSync(marker)) {
  fs.writeFileSync(
    marker,
    'Generated by scripts/ensure-public-output.cjs for Vercel outputDirectory.\n',
  );
}
